//
//  TarotCardData.swift
//  LIFESPACE
//
//  Created by Mario Sbardella on 2025-11-14.
//

import Foundation

let tarotCards: [TarotCard] = [

    // MARK: - Major Arcana (0–21)
    TarotCard(name: "The Fool",        image: "tarot_fool",        meaning: "Folly, mania, extravagance, intoxication, delirium, frenzy, bewrayment. A new beginning."),
    TarotCard(name: "The Magician",    image: "tarot_magician",    meaning: "Skill, diplomacy, address, subtlety; sickness, pain, loss, disaster, snares of enemies; self-confidence, will; the Querent, if male."),
    TarotCard(name: "The High Priestess", image: "tarot_high_priestess", meaning: "Secrets, mystery, the future as yet unrevealed; the woman who interests the Querent, if male; the Querent herself, if female; silence, tenacity; mystery, wisdom, science."),
    TarotCard(name: "The Empress",     image: "tarot_empress",     meaning: "Fruitfulness, action, initiative, length of days; the unknown, clandestine; also difficulty, doubt, ignorance."),
    TarotCard(name: "The Emperor",     image: "tarot_emperor",     meaning: "Stability, power, protection, realization; a great person; aid, reason, conviction; authority and will."),
    TarotCard(name: "The Hierophant",  image: "tarot_hierophant",  meaning: "Marriage, alliance, captivity, servitude; mercy and goodness; inspiration; the man to whom the Querent has recourse."),
    TarotCard(name: "The Lovers",      image: "tarot_lovers",      meaning: "Attraction, love, beauty, trials overcome."),
    TarotCard(name: "The Chariot",     image: "tarot_chariot",     meaning: "Succour, providence; war, triumph, presumption, vengeance, trouble."),
    TarotCard(name: "Strength",        image: "tarot_strength",    meaning: "Power, energy, action, courage, magnanimity; complete success and honours."),
    TarotCard(name: "The Hermit",      image: "tarot_hermit",      meaning: "Prudence, circumspection; treason, dissimulation, roguery, corruption."),
    TarotCard(name: "Wheel of Fortune", image: "tarot_wheel_of_fortune", meaning: "Destiny, fortune, success, elevation, luck, felicity."),
    TarotCard(name: "Justice",         image: "tarot_justice",     meaning: "Equity, rightness, probity, executive; triumph of the deserving side in law."),
    TarotCard(name: "The Hanged Man",  image: "tarot_hanged_man",  meaning: "Wisdom, circumspection, discernment, trials, sacrifice, intuition, divination, prophecy."),
    TarotCard(name: "Death",           image: "tarot_death",       meaning: "End, mortality, destruction, corruption; for a man, loss of a benefactor; for a woman, contrarieties; for a maid, failed marriage projects."),
    TarotCard(name: "Temperance",      image: "tarot_temperance",  meaning: "Economy, moderation, frugality, management, accommodation."),
    TarotCard(name: "The Devil",       image: "tarot_devil",       meaning: "Ravage, violence, vehemence, extraordinary efforts, force, fatality; predestined forces not necessarily evil."),
    TarotCard(name: "The Tower",       image: "tarot_tower",       meaning: "Misery, distress, indigence, adversity, calamity, disgrace, deception, ruin; unforeseen catastrophe."),
    TarotCard(name: "The Star",        image: "tarot_star",        meaning: "Loss, theft, privation, abandonment; hope and bright prospects."),
    TarotCard(name: "The Moon",        image: "tarot_moon",        meaning: "Hidden enemies, danger, calumny, darkness, terror, deception, occult forces, error."),
    TarotCard(name: "The Sun",         image: "tarot_sun",         meaning: "Material happiness, fortunate marriage, contentment."),
    TarotCard(name: "The Last Judgement",       image: "tarot_judgement",   meaning: "Change of position, renewal, outcome; total loss through lawsuit."),
    TarotCard(name: "The World",       image: "tarot_world",       meaning: "Assured success, recompense, voyage, route, emigration, flight, change of place."),

    // MARK: - Wands (Fire)
    TarotCard(name: "Ace of Wands",        image: "tarot_wands_ace",        meaning: "Creation, invention, enterprise, beginning; birth, family, origin, and in a sense the virility which is behind them; the starting point of enterprises; according to another account, money, fortune, inheritance. Trickery. Small success. Favourable chance."),
    TarotCard(name: "Two of Wands",        image: "tarot_wands_2",          meaning: "Between the alternative readings there is no marriage possible; on the one hand, riches, fortune, magnificence; on the other, physical suffering, disease, chagrin, sadness, mortification. Accord, security, contention."),
    TarotCard(name: "Three of Wands",      image: "tarot_wands_3",          meaning: "He symbolizes established strength, enterprise, effort, trade, commerce, discovery; those are his ships, bearing his merchandise, which are sailing over the sea. The card also signifies able co-operation in business, as if the successful merchant prince were looking from his side towards yours with a view to help you. Calm, unity, progress."),
    TarotCard(name: "Four of Wands",       image: "tarot_wands_4",          meaning: "They are for once almost on the surface – country life, haven of refuge, a species of domestic harvest-home, repose, concord, harmony, prosperity, peace, and the perfected work of these. Insomnia, a subject of reflection, journey near at hand."),
    TarotCard(name: "Five of Wands",       image: "tarot_wands_5",          meaning: "Imitation, as, for example, sham fight, but also the strenuous competition and struggle of the search after riches and fortune. In this sense it connects with the battle of life. Hence some attributions say that it is a card of gold, gain, opulence. Vigils, determination, regularity."),
    TarotCard(name: "Six of Wands",        image: "tarot_wands_6",          meaning: "The card has been so designed that it can cover several significations; on the surface, it is a victor triumphing, but it is also great news, such as might be carried in state by the King's courier; it is expectation crowned with its own desire, the crown of hope, and so forth. Servants may lose the confidence of their masters; a young lady may be betrayed by a friend. Irritability, success, abundance."),
    TarotCard(name: "Seven of Wands",      image: "tarot_wands_7",          meaning: "It is a card of valour, for, on the surface, six are attacking one, who has, however, the vantage position. On the intellectual plane, it signifies discussion, wordy strife; in business – negotiations, war of trade, barter, competition. It is further a card of success, for the combatant is on the top and his enemies may be unable to reach him. News, infirmity, intrigue."),
    TarotCard(name: "Eight of Wands",      image: "tarot_wands_8",          meaning: "Activity in undertakings, the path of such activity, swiftness, as that of an express messenger; great haste, great hope, speed towards an end which promises assured felicity; generally, that which is on the move; also the arrows of love. Domestic disputes for a married person. New knowledge, marriage, reverse."),
    TarotCard(name: "Nine of Wands",       image: "tarot_wands_9",          meaning: "The card signifies strength in opposition. If attacked, the person will meet an onslaught boldly; and his build shews that he may prove a formidable antagonist. With this main significance there are all its possible adjuncts – delay, suspension, adjournment. Generally speaking, a bad card. A good friend."),
    TarotCard(name: "Ten of Wands",        image: "tarot_wands_10",         meaning: "The chief meaning is oppression simply, but it is also fortune, gain, any kind of success, and then it is the oppression of these things. It is also a card of false-seeming, disguise, perfidy. The place which the figure is approaching may suffer from the rods that he carries."),
    TarotCard(name: "Page of Wands",       image: "tarot_wands_page",       meaning: "Dark young man, faithful, a lover, an envoy, a postman. Beside a man, he will bear favourable testimony concerning him. A dangerous rival, if followed by the Page of Cups. Has the chief qualities of his suit. He may signify family intelligence. Young man of family in search of young lady. Disquiet, dispute, dangerous illness."),
    TarotCard(name: "Knight of Wands",     image: "tarot_wands_knight",     meaning: "Departure, absence, flight, emigration. A dark young man, friendly. Change of residence. Alternatively, alienation. Intimacy, lively debate, serious matters."),
    TarotCard(name: "Queen of Wands",      image: "tarot_wands_queen",      meaning: "A dark woman, countrywoman, friendly, chaste, loving, honourable. If the card beside her signifies a man, she is well disposed towards him; if a woman, she is interested in the Querent. Also, love of money, or a certain success in business. A good harvest, which may be taken in several senses. Sincere friends; deception by women; great debate."),
    TarotCard(name: "King of Wands",       image: "tarot_wands_king",       meaning: "Dark man; friendly; conscientious; honest; generally married; may mean news of unexpected inheritance. Generally favourable; may signify a good marriage. Minor counsel, consultation; great honour."),

    // MARK: - Cups (Water)
    TarotCard(name: "Ace of Cups",         image: "tarot_cups_ace",         meaning: "House of the true heart, joy, content, abode, nourishment, abundance, fertility; Holy Table, felicity hereof. Inflexible will, unalterable law. Trickery, small success, favourable chance."),
    TarotCard(name: "Two of Cups",         image: "tarot_cups_2",           meaning: "Love, passion, friendship, affinity, union, concord, sympathy, the interrelation of the sexes, and – as a suggestion apart from all offices of divination – that desire which is not in Nature, but by which Nature is sanctified. Favourable in things of pleasure and business, as well as love; also wealth and honour. Accord, security, contention."),
    TarotCard(name: "Three of Cups",       image: "tarot_cups_3",           meaning: "The conclusion of any matter in plenty, perfection and merriment; happy issue, victory, fulfilment, solace, healing. Unexpected advancement for a military man. Calm, unity, progress."),
    TarotCard(name: "Four of Cups",        image: "tarot_cups_4",           meaning: "Weariness, disgust, aversion, imaginary vexations, as if the wine of this world had caused satiety only; another wine, as if a fairy gift, is now offered the wastrel, but he sees no consolation therein. This is also a card of blended pleasure. Contrarieties. Journey near at hand, subject of reflection, insomnia."),
    TarotCard(name: "Five of Cups",        image: "tarot_cups_5",           meaning: "It is a card of loss, but something remains over; three have been taken, but two are left; it is a card of inheritance, patrimony, transmission, but not corresponding to expectations."),
    TarotCard(name: "Six of Cups",         image: "tarot_cups_6",           meaning: "A card of the past and of memories, looking back, as – for example – on childhood; happiness, enjoyment, but coming rather from the past; things that have vanished. Another reading reverses this, giving new relations, new knowledge, new environment, and then the children are disporting in an unfamiliar precinct. Pleasant memories."),
    TarotCard(name: "Seven of Cups",       image: "tarot_cups_7",           meaning: "Fairy favours, images of reflection, sentiment, imagination, things seen in the glass of contemplation; some attainment in these degrees, but nothing permanent or substantial is suggested. Fair child; idea, design, resolve, movement."),
    TarotCard(name: "Eight of Cups",       image: "tarot_cups_8",           meaning: "Deserting enterprise, undertaking or previous concern."),
    TarotCard(name: "Nine of Cups",        image: "tarot_cups_9",           meaning: "Concord, contentment, physical bien-être; also victory, success, advantage; satisfaction for the Querent or person for whom the consultation is made."),
    TarotCard(name: "Ten of Cups",         image: "tarot_cups_10",          meaning: "Contentment, repose of the entire heart; the perfection of that state; also perfection of human love and friendship; if with several picture-cards, a person who is taking charge of the Querent's interests; also the town, village or country inhabited by the Querent. For a male Querent, a good marriage and one beyond his expectations."),
    TarotCard(name: "Page of Cups",        image: "tarot_cups_page",        meaning: "Fair young man, one impelled to render service and with whom the Querent will be connected; a studious youth; news, message; application, reflection, meditation; also these things directed to business. Good augury; also a young man who is unfortunate in love."),
    TarotCard(name: "Knight of Cups",      image: "tarot_cups_knight",      meaning: "Arrival, approach – sometimes that of a messenger; advances, proposition, demeanour, invitation, incitement. A visit from a friend, who will bring unexpected money to the Querent. Intimacy, lively debate, serious matters."),
    TarotCard(name: "Queen of Cups",       image: "tarot_cups_queen",       meaning: "Good, fair woman; honest, devoted woman, who will do service to the Querent; loving intelligence, and hence the gift of vision; success, happiness, pleasure; also wisdom, virtue; a perfect spouse and a good mother. Sometimes denotes a woman of equivocal character. Sincere friends. Deception by women. Great debate."),
    TarotCard(name: "King of Cups",        image: "tarot_cups_king",        meaning: "Fair man, man of business, law, or divinity; responsible, disposed to oblige the Querent; also equity, art and science, including those who profess science, law and art; creative intelligence. Beware of ill-will on the part of a man of position, and of hypocrisy pretending to help."),

    // MARK: - Swords (Air)
    TarotCard(name: "Ace of Swords",       image: "tarot_swords_ace",       meaning: "Triumph, the excessive degree in everything, conquest, triumph of force. It is a card of great force, in love as well as in hatred. The crown may carry a much higher significance than comes usually within the sphere of fortune-telling. Great prosperity or great misery."),
    TarotCard(name: "Two of Swords",       image: "tarot_swords_2",         meaning: "Conformity and the equipoise which it suggests, courage, friendship, concord in a state of arms; another reading gives tenderness, affection, intimacy. Gifts for a lady, influential protection for a man in search of help."),
    TarotCard(name: "Three of Swords",     image: "tarot_swords_3",         meaning: "Removal, absence, delay, division, rupture, dispersion, and all that the design signifies naturally, being too simple and obvious to call for specific enumeration. For a woman, the flight of her lover."),
    TarotCard(name: "Four of Swords",      image: "tarot_swords_4",         meaning: "Vigilance, retreat, solitude, hermit's repose, exile, tomb and coffin. It is these last that have suggested the design. A bad card."),
    TarotCard(name: "Five of Swords",      image: "tarot_swords_5",         meaning: "Degradation, destruction, revocation, infamy, dishonour, loss, with the variants and analogues of these. An attack on the fortune of the Querent."),
    TarotCard(name: "Six of Swords",       image: "tarot_swords_6",         meaning: "Journey by water, route, way, envoy, commissionary, expedient. The voyage will be pleasant."),
    TarotCard(name: "Seven of Swords",     image: "tarot_swords_7",         meaning: "Design, attempt, wish, hope, confidence; also quarrelling, a plan that may fail, annoyance. The design is uncertain in its import, because the significations are widely at variance with each other. Dark girl; a good card; it promises a country life after a competence has been secured."),
    TarotCard(name: "Eight of Swords",     image: "tarot_swords_8",         meaning: "Bad news, violent chagrin, crisis, censure, power in trammels, conflict, calumny; also sickness. For a woman, scandal spread in her respect."),
    TarotCard(name: "Nine of Swords",      image: "tarot_swords_9",         meaning: "Death, failure, miscarriage, delay, deception, disappointment, despair. An ecclesiastic, a priest; generally, a card of bad omen."),
    TarotCard(name: "Ten of Swords",       image: "tarot_swords_10",        meaning: "Whatsoever is intimated by the design; also pain, affliction, tears, sadness, desolation. It is not especially a card of violent death. Followed by Ace and King, imprisonment; for girl or wife, treason on the part of friends. Change; new condition; condemnation."),
    TarotCard(name: "Page of Swords",      image: "tarot_swords_page",      meaning: "Authority, overseeing, secret service, vigilance, spying, examination, and the qualities thereto belonging. An indiscreet person will pry into the Querent's secrets."),
    TarotCard(name: "Knight of Swords",    image: "tarot_swords_knight",    meaning: "Skill, bravery, capacity, defence, address, enmity, wrath, war, destruction, opposition, resistance, ruin. There is therefore a sense in which the card signifies death, but it carries this meaning only in its proximity to other cards of fatality. A soldier, man of arms, satellite, stipendiary; heroic action predicted for soldier."),
    TarotCard(name: "Queen of Swords",     image: "tarot_swords_queen",     meaning: "Widowhood, female sadness and embarrassment, absence, sterility, mourning, privation, separation. Sincere friends; deception by women; great debate."),
    TarotCard(name: "King of Swords",      image: "tarot_swords_king",      meaning: "Whatsoever arises out of the idea of judgment and all its connexions – power, command, authority, militant intelligence, law, offices of the crown, and so forth. A lawyer, senator, doctor."),

    // MARK: - Pentacles (Earth)
    TarotCard(name: "Ace of Pentacles",    image: "tarot_pentacles_ace",    meaning: "Perfect contentment, felicity, ecstasy; also speedy intelligence; gold. It shews prosperity, comfortable material conditions, but whether these are of advantage to the possessor will depend on whether the card is reversed or not. The most favourable of all cards."),
    TarotCard(name: "Two of Pentacles",    image: "tarot_pentacles_2",      meaning: "On the one hand it is represented as a card of gaiety, recreation and its connexions, which is the subject of the design; but it is read also as news and messages in writing, as obstacles, agitation, trouble, embroilment. Troubles are more imaginary than real."),
    TarotCard(name: "Three of Pentacles",  image: "tarot_pentacles_3",      meaning: "Métier, trade, skilled labour; usually, however, regarded as a card of nobility, aristocracy, renown, glory. If for a man, celebrity for his eldest son."),
    TarotCard(name: "Four of Pentacles",   image: "tarot_pentacles_4",      meaning: "The surety of possessions, cleaving to that which one has, gift, legacy, inheritance. For a bachelor, pleasant news from a lady."),
    TarotCard(name: "Five of Pentacles",   image: "tarot_pentacles_5",      meaning: "The card foretells material trouble above all, whether in the form illustrated – that is, destitution – or otherwise. For some cartomancists, it is a card of love and lovers – wife, husband, friend, mistress; also concordance, affinities. Conquest of fortune by reason."),
    TarotCard(name: "Six of Pentacles",    image: "tarot_pentacles_6",      meaning: "Presents, gifts, gratification; another account says attention, vigilance; The present must not be relied on."),
    TarotCard(name: "Seven of Pentacles",  image: "tarot_pentacles_7",      meaning: "These are exceedingly contradictory; in the main, it is a card of money, business, barter; but one reading gives altercation, quarrel; purification. Improved position for a lady's future husband. News; physical or mental weakness; intrigue."),
    TarotCard(name: "Eight of Pentacles",  image: "tarot_pentacles_8",      meaning: "Work, employment, commission, craftsmanship, skill in craft and business, perhaps in the preparatory stage. A young man in business who has relations with the Querent; a dark girl."),
    TarotCard(name: "Nine of Pentacles",   image: "tarot_pentacles_9",      meaning: "Prudence, safety, success, accomplishment, certitude, discernment. Prompt fulfilment of what is presaged by neighbouring cards."),
    TarotCard(name: "Ten of Pentacles",    image: "tarot_pentacles_10",     meaning: "Gain, riches; family matters, archives, extraction, the abode of a family. Represents house or dwelling, and derives its value from other cards. "),
    TarotCard(name: "Page of Pentacles",   image: "tarot_pentacles_page",   meaning: "Application, study, scholarship, reflection; another reading says news, messages and the bringer thereof; also rule, management."),
    TarotCard(name: "Knight of Pentacles", image: "tarot_pentacles_knight", meaning: "Utility, serviceableness, interest, responsibility, rectitude – all on the normal and external plane. A useful man; useful discoveries."),
    TarotCard(name: "Queen of Pentacles",  image: "tarot_pentacles_queen",  meaning: "Opulence, generosity, magnificence, security, liberty. Dark woman; presents from a rich relative; rich and happy marriage for a young man."),
    TarotCard(name: "King of Pentacles",   image: "tarot_pentacles_king",   meaning: "Valour, realizing intelligence, business and normal intellectual aptitude, sometimes mathematical gifts and attainments of this kind; success in these paths."),

    // MARK: - Major Arcana (Reversed)
    TarotCard(name: "The Fool (Reversed)",        image: "tarot_fool_rev",        meaning: "Negligence, absence, distribution, carelessness, apathy, nullity, vanity."),
    TarotCard(name: "The Magician (Reversed)",    image: "tarot_magician_rev",    meaning: "Physician, Magus, mental disease, disgrace, disquiet."),
    TarotCard(name: "The High Priestess (Reversed)", image: "tarot_high_priestess_rev", meaning: "Passion, moral or physical ardour, conceit, surface knowledge."),
    TarotCard(name: "The Empress (Reversed)",     image: "tarot_empress_rev",     meaning: "Light, truth, the unravelling of involved matters, public rejoicings; vacillation."),
    TarotCard(name: "The Emperor (Reversed)",     image: "tarot_emperor_rev",     meaning: "Benevolence, compassion, credit; confusion to enemies, obstruction, immaturity."),
    TarotCard(name: "The Hierophant (Reversed)",  image: "tarot_hierophant_rev",  meaning: "Society, good understanding, concord, overkindness, weakness."),
    TarotCard(name: "The Lovers (Reversed)",      image: "tarot_lovers_rev",      meaning: "Failure, foolish designs; marriage frustrated; contrarieties of all kinds."),
    TarotCard(name: "The Chariot (Reversed)",     image: "tarot_chariot_rev",     meaning: "Riot, quarrel, dispute, litigation, defeat."),
    TarotCard(name: "Strength (Reversed)",        image: "tarot_strength_rev",    meaning: "Despotism, abuse of power, weakness, discord, disgrace."),
    TarotCard(name: "The Hermit (Reversed)",      image: "tarot_hermit_rev",      meaning: "Concealment, disguise, policy, fear, unreasoned caution."),
    TarotCard(name: "Wheel of Fortune (Reversed)", image: "tarot_wheel_of_fortune_rev", meaning: "Increase, abundance, superfluity."),
    TarotCard(name: "Justice (Reversed)",         image: "tarot_justice_rev",     meaning: "Law in all its departments, legal complications, bigotry, bias, excessive severity."),
    TarotCard(name: "The Hanged Man (Reversed)",  image: "tarot_hanged_man_rev",  meaning: "Selfishness, the crowd, body politic."),
    TarotCard(name: "Death (Reversed)",           image: "tarot_death_rev",       meaning: "Inertia, sleep, lethargy, petrifaction, somnambulism; hope destroyed."),
    TarotCard(name: "Temperance (Reversed)",      image: "tarot_temperance_rev",  meaning: "Things connected with churches, religions, sects, the priesthood; disunion; unfortunate combinations; competing interests."),
    TarotCard(name: "The Devil (Reversed)",       image: "tarot_devil_rev",       meaning: "Evil fatality, weakness, pettiness, blindness."),
    TarotCard(name: "The Tower (Reversed)",       image: "tarot_tower_rev",       meaning: "The same in lesser degree; oppression, imprisonment, tyranny."),
    TarotCard(name: "The Star (Reversed)",        image: "tarot_star_rev",        meaning: "Arrogance, haughtiness, impotence."),
    TarotCard(name: "The Moon (Reversed)",        image: "tarot_moon_rev",        meaning: "Instability, inconstancy, silence; lesser degrees of deception and error."),
    TarotCard(name: "The Sun (Reversed)",         image: "tarot_sun_rev",         meaning: "Material happiness, fortunate marriage, contentment."),
    TarotCard(name: "Judgement (Reversed)",       image: "tarot_judgement_rev",   meaning: "Weakness, pusillanimity, simplicity; deliberation, decision, sentence."),
    TarotCard(name: "The World (Reversed)",       image: "tarot_world_rev",       meaning: "Inertia, fixity, stagnation, permanence."),

    // MARK: - Wands (Reversed)
    TarotCard(name: "Ace of Wands (Reversed)",        image: "tarot_wands_ace_rev",        meaning: "Fall, decadence, ruin, perdition, to perish; also a certain clouded joy. A sign of birth. Enemies. Debauchery. Dishonour."),
    TarotCard(name: "Two of Wands (Reversed)",        image: "tarot_wands_2_rev",          meaning: "Surprise, wonder, enchantment, emotion, trouble, fear. Mistrust, apprehension, reconciliation."),
    TarotCard(name: "Three of Wands (Reversed)",      image: "tarot_wands_3_rev",          meaning: "The end of troubles, suspension or cessation of adversity, toil and disappointment. Safety, serenity, great success."),
    TarotCard(name: "Four of Wands (Reversed)",       image: "tarot_wands_4_rev",          meaning: "The meaning remains unaltered; it is prosperity, increase, felicity, beauty, embellishment. Dispute, disquiet, walks abroad."),
    TarotCard(name: "Five of Wands (Reversed)",       image: "tarot_wands_5_rev",          meaning: "Litigation, disputes, trickery, contradiction. Reverse, hesitation, order."),
    TarotCard(name: "Six of Wands (Reversed)",        image: "tarot_wands_6_rev",          meaning: "Apprehension, fear, as of a victorious enemy at the gate; treachery, disloyalty, as of gates being opened to the enemy; also indefinite delay. Downfall."),
    TarotCard(name: "Seven of Wands (Reversed)",      image: "tarot_wands_7_rev",          meaning: "Perplexity, embarrassments, anxiety. It is also a caution against indecision. Women of no repute, joy, quarrellers."),
    TarotCard(name: "Eight of Wands (Reversed)",      image: "tarot_wands_8_rev",          meaning: "Arrows of jealousy, internal dispute, stingings of conscience, quarrels; and domestic disputes for persons who are married. Misfortune, a spectacle, error."),
    TarotCard(name: "Nine of Wands (Reversed)",       image: "tarot_wands_9_rev",          meaning: "Obstacles, adversity, calamity. A small profit, imprudence, usury."),
    TarotCard(name: "Ten of Wands (Reversed)",        image: "tarot_wands_10_rev",         meaning: "Contrarieties, difficulties, intrigues."),
    TarotCard(name: "Page of Wands (Reversed)",       image: "tarot_wands_page_rev",       meaning: "Anecdotes, announcements, evil news. Also indecision and the instability which accompanies it. Bad news. Society, idleness, privation."),
    TarotCard(name: "Knight of Wands (Reversed)",     image: "tarot_wands_knight_rev",     meaning: "Rupture, division, interruption, discord. For a woman, marriage, but probably frustrated. Susceptibility, a duel or personal encounter, alliance."),
    TarotCard(name: "Queen of Wands (Reversed)",      image: "tarot_wands_queen_rev",      meaning: "Good, economical, obliging, serviceable. Signifies also – but in certain positions and in the neighbourhood of other cards tending in such directions – opposition, jealousy, even deceit and infidelity. Goodwill towards the Querent, but without the opportunity to exercise it. Work, gluttony, bad company."),
    TarotCard(name: "King of Wands (Reversed)",       image: "tarot_wands_king_rev",       meaning: "Good but severe; austere yet tolerant. Advice that should be followed. Projects, commerce."),

    // MARK: - Cups (Reversed)
    TarotCard(name: "Ace of Cups (Reversed)",         image: "tarot_cups_ace_rev",         meaning: "House of the false heart, mutation, instability, revolution. Unexpected change of position. Enemies, debauchery, dishonour."),
    TarotCard(name: "Two of Cups (Reversed)",         image: "tarot_cups_2_rev",           meaning: "Passion; mistrust; apprehension; reconciliation."),
    TarotCard(name: "Three of Cups (Reversed)",       image: "tarot_cups_3_rev",           meaning: "Expedition, dispatch, achievement, end; excess in physical enjoyment; pleasures of the senses. Safety, serenity, great success."),
    TarotCard(name: "Four of Cups (Reversed)",        image: "tarot_cups_4_rev",           meaning: "Novelty, presage, new instruction, new relations. Presentiment. Dispute, disquiet, walks abroad."),
    TarotCard(name: "Five of Cups (Reversed)",        image: "tarot_cups_5_rev",           meaning: "News, alliances, affinity, consanguinity, ancestry, return, false projects. Return of some relative who has not been seen for long. Reverse; hesitation; order."),
    TarotCard(name: "Six of Cups (Reversed)",         image: "tarot_cups_6_rev",           meaning: "The future, renewal, that which will come to pass presently. Inheritance to fall in quickly."),
    TarotCard(name: "Seven of Cups (Reversed)",       image: "tarot_cups_7_rev",           meaning: "Desire, will, determination, project. Success, if accompanied by the Three of Cups."),
    TarotCard(name: "Eight of Cups (Reversed)",       image: "tarot_cups_8_rev",           meaning: "Great joy, happiness, feasting. Perfect satisfaction. Misfortune, a spectacle, error."),
    TarotCard(name: "Nine of Cups (Reversed)",        image: "tarot_cups_9_rev",           meaning: "Truth, loyalty, liberty; but the readings vary and include mistakes, imperfections, etc. Good business."),
    TarotCard(name: "Ten of Cups (Reversed)",         image: "tarot_cups_10_rev",          meaning: "For a male Querent: a good marriage beyond expectations. End of of the false heart; indignation; violence. Expectation justified, disappointment; event; happening."),
    TarotCard(name: "Page of Cups (Reversed)",        image: "tarot_cups_page_rev",        meaning: "Taste, inclination, attachment, seduction, deception, artifice. Obstacles of all kinds."),
    TarotCard(name: "Knight of Cups (Reversed)",      image: "tarot_cups_knight_rev",      meaning: "Trickery, artifice, subtlety, swindling, duplicity, fraud. Irregularity. Susceptibility. A duel or personal encounter; alliance."),
    TarotCard(name: "Queen of Cups (Reversed)",       image: "tarot_cups_queen_rev",       meaning: "The accounts vary; good woman; otherwise, distinguished woman but one not to be trusted; perverse woman; vice, dishonour, depravity. A rich marriage for a man and a distinguished one for a woman. Work. Gluttony; bad company."),
    TarotCard(name: "King of Cups (Reversed)",        image: "tarot_cups_king_rev",        meaning: "Dishonest, double-dealing man; roguery, exaction, injustice, vice, scandal, pillage, considerable loss."),

    // MARK: - Swords (Reversed)
    TarotCard(name: "Ace of Swords (Reversed)",       image: "tarot_swords_ace_rev",       meaning: "The same, but the results are disastrous; another account says – conception, childbirth, augmentation, multiplicity. Marriage broken off, for a woman, through her own imprudence."),
    TarotCard(name: "Two of Swords (Reversed)",       image: "tarot_swords_2_rev",         meaning: "Imposture, falsehood, duplicity, disloyalty. Dealings with rogues. Mistrust, apprehension, reconciliation."),
    TarotCard(name: "Three of Swords (Reversed)",     image: "tarot_swords_3_rev",         meaning: "Mental alienation, error, loss, distraction, disorder, confusion. A meeting with one whom the Querent has compromised; also a nun."),
    TarotCard(name: "Four of Swords (Reversed)",      image: "tarot_swords_4_rev",         meaning: "Wise administration, circumspection, economy, avarice, precaution, testament. A certain success following wise administration."),
    TarotCard(name: "Five of Swords (Reversed)",      image: "tarot_swords_5_rev",         meaning: "Degradation, destruction, revocation, infamy, dishonour, loss."),
    TarotCard(name: "Six of Swords (Reversed)",       image: "tarot_swords_6_rev",         meaning: "Declaration, confession, publicity; one account says that it is a proposal of love. Unfavourable issue of lawsuit."),
    TarotCard(name: "Seven of Swords (Reversed)",     image: "tarot_swords_7_rev",         meaning: "Good advice that’s probably neglected, counsel, instruction, slander, babbling."),
    TarotCard(name: "Eight of Swords (Reversed)",     image: "tarot_swords_8_rev",         meaning: "Disquiet, difficulty, opposition, accident, treachery; what is unforeseen; fatality. Departure of a relative."),
    TarotCard(name: "Nine of Swords (Reversed)",      image: "tarot_swords_9_rev",         meaning: "Imprisonment, suspicion, doubt, reasonable fear, shame. Good ground for suspicion against a doubtful person."),
    TarotCard(name: "Ten of Swords (Reversed)",       image: "tarot_swords_10_rev",        meaning: "Advantage, profit, success, favour, but none of these are permanent; also power and authority. Victory and consequent fortune for a soldier in war. Expectation justified; disappointment; event; happening."),
    TarotCard(name: "Page of Swords (Reversed)",      image: "tarot_swords_page_rev",      meaning: "Gossip, spying with evil intentions, eavesdropping, sickness."),
    TarotCard(name: "Knight of Swords (Reversed)",    image: "tarot_swords_knight_rev",    meaning: "Imprudence, incapacity, extravagance. Dispute with an imbecile person; for a woman, struggle with a rival, who will be conquered."),
    TarotCard(name: "Queen of Swords (Reversed)",     image: "tarot_swords_queen_rev",     meaning: "Malice, bigotry, artifice, prudery, bale, deceit. A bad woman with ill-will toward Querent. Work; gluttony; bad company."),
    TarotCard(name: "King of Swords (Reversed)",      image: "tarot_swords_king_rev",      meaning: "Cruelty, perversity, barbarity, perfidy, evil intention. A bad man; also a caution to put an end to a ruinous lawsuit."),

    // MARK: - Pentacles (Reversed)
    TarotCard(name: "Ace of Pentacles (Reversed)",    image: "tarot_pentacles_ace_rev",    meaning: "The evil side of wealth, bad intelligence; also great riches, a share in the finding of treasure."),
    TarotCard(name: "Two of Pentacles (Reversed)",    image: "tarot_pentacles_2_rev",      meaning: "Enforced gaiety, simulated enjoyment, literal sense, handwriting, composition, letters of exchange. Bad omen, ignorance, injustice."),
    TarotCard(name: "Three of Pentacles (Reversed)",  image: "tarot_pentacles_3_rev",      meaning: "Mediocrity, in work and otherwise, puerility, pettiness, weakness."),
    TarotCard(name: "Four of Pentacles (Reversed)",   image: "tarot_pentacles_4_rev",      meaning: "Suspense, delay, opposition. Observation, hindrances."),
    TarotCard(name: "Five of Pentacles (Reversed)",   image: "tarot_pentacles_5_rev",      meaning: "Disorder, chaos, ruin, discord, profligacy. Troubles in love."),
    TarotCard(name: "Six of Pentacles (Reversed)",    image: "tarot_pentacles_6_rev",      meaning: "Desire, cupidity, envy, jealousy, illusion. A check on the Querent's ambition."),
    TarotCard(name: "Seven of Pentacles (Reversed)",  image: "tarot_pentacles_7_rev",      meaning: "Cause for anxiety regarding money which it may be proposed to lend. Impatience, apprehension, suspicion. Women of no repute; joy; quarrellers."),
    TarotCard(name: "Eight of Pentacles (Reversed)",  image: "tarot_pentacles_8_rev",      meaning: "Voided ambition, vanity, cupidity, exaction, usury. It may also signify the possession of skill, in the sense of the ingenious mind turned to cunning deceit and intrigue. The Querent will be compromised in a matter of money-lending."),
    TarotCard(name: "Nine of Pentacles (Reversed)",   image: "tarot_pentacles_9_rev",      meaning: "Roguery, deception, voided project, bad faith. Vain hopes."),
    TarotCard(name: "Ten of Pentacles (Reversed)",    image: "tarot_pentacles_10_rev",     meaning: "Chance, fatality, loss, robbery, games of hazard; sometimes gift, dowry, pension. An occasion which may be fortunate or otherwise. Expectation justified. Disappointment. Event; happening."),
    TarotCard(name: "Page of Pentacles (Reversed)",   image: "tarot_pentacles_page_rev",   meaning: "Prodigality, dissipation, liberality, luxury; unfavourable news. Sometimes degradation and sometimes pillage."),
    TarotCard(name: "Knight of Pentacles (Reversed)", image: "tarot_pentacles_knight_rev", meaning: "Inertia, idleness, repose of that kind, stagnation; also placidity, discouragement, carelessness. A brave man out of employment."),
    TarotCard(name: "Queen of Pentacles (Reversed)",  image: "tarot_pentacles_queen_rev",  meaning: "Evil, suspicion, suspense, fear, mistrust. An illness."),
    TarotCard(name: "King of Pentacles (Reversed)",   image: "tarot_pentacles_king_rev",   meaning: "Vice, weakness, ugliness, perversity, corruption, peril. An old and vicious man.")
]

